def gen(rng, size):
    n = rng.randint(2, 10)
    steps = max(1, min(size, 100))
    r, c = 0, 0
    commands = []
    for _ in range(steps):
        options = []
        if r > 0:
            options.append('UP')
        if r < n - 1:
            options.append('DOWN')
        if c > 0:
            options.append('LEFT')
        if c < n - 1:
            options.append('RIGHT')
        cmd = rng.choice(options)
        if cmd == 'UP':
            r -= 1
        elif cmd == 'DOWN':
            r += 1
        elif cmd == 'LEFT':
            c -= 1
        else:
            c += 1
        commands.append(cmd)
    return [n, commands]

