class Solution:
    def finalPositionOfSnake(self, n: int, commands) -> int:
        pos = 0
        for cmd in commands:
            r, c = divmod(pos, n)
            if cmd == 'UP':
                r -= 1
            elif cmd == 'DOWN':
                r += 1
            elif cmd == 'LEFT':
                c -= 1
            elif cmd == 'RIGHT':
                c += 1
            pos = r * n + c
        return pos

