var finalPositionOfSnake = function(n, commands) {
    let r = 0, c = 0;
    for (const cmd of commands) {
        if (cmd === 'UP') r--;
        else if (cmd === 'DOWN') r++;
        else if (cmd === 'LEFT') c--;
        else if (cmd === 'RIGHT') c++;
    }
    return r * n + c;
};
